class Solution:
    def minDays(self, bloomDay, m, k):
        """
        :type bloomDay: List[int]
        :type m: int
        :type k: int
        :rtype: int
        """
        if len(bloomDay) < m * k:
            return -1

        def canMakeBouquets(days):
            bouquets = 0
            consecutive = 0
            for bloom in bloomDay:
                if bloom <= days:
                    consecutive += 1
                    if consecutive == k:
                        bouquets += 1
                        consecutive = 0
                else:
                    consecutive = 0
            return bouquets >= m

        left, right = min(bloomDay), max(bloomDay)
        result = right

        while left <= right:
            mid = (left + right) // 2
            if canMakeBouquets(mid):
                result = mid
                right = mid - 1
            else:
                left = mid + 1

        return result
